var tilesX = Math.Clamp(GetInt(parameters, "tilesX", 2), 1, 4);
var tilesY = Math.Clamp(GetInt(parameters, "tilesY", 2), 1, 4);
var layout = GetChoice(parameters, "layout", "grid");
var overlap = GetFloat(parameters, "overlap", 0f);
var gap = GetFloat(parameters, "gap", 0f);

var tileSize = context.TileSize;
var gapPixels = (int)(gap * tileSize);

int outputW, outputH;

switch (layout)
{
    case "horizontalStrip":
        outputW = tileSize * tilesX + gapPixels * (tilesX - 1);
        outputH = tileSize;
        break;
    case "verticalStrip":
        outputW = tileSize;
        outputH = tileSize * tilesY + gapPixels * (tilesY - 1);
        break;
    default: // grid
        outputW = tileSize * tilesX + gapPixels * (tilesX - 1);
        outputH = tileSize * tilesY + gapPixels * (tilesY - 1);
        break;
}

var buffer = new PixelBuffer(outputW, outputH);

// Initialize to transparent
buffer.ParallelForEachPixel((x, y) => buffer.SetPixel(x, y, 0f, 0f, 0f, 0f));

for (var ty = 0; ty < tilesY; ty++)
{
    for (var tx = 0; tx < tilesX; tx++)
    {
        var inputIndex = ty * tilesX + tx;
        var input = inputIndex < inputs.Length ? inputs[inputIndex] : null;
        if (input == null) continue;

        var destX = tx * (tileSize + gapPixels);
        var destY = ty * (tileSize + gapPixels);

        for (var y = 0; y < tileSize; y++)
        {
            for (var x = 0; x < tileSize; x++)
            {
                var bx = destX + x;
                var by = destY + y;
                if (bx >= outputW || by >= outputH) continue;

                var (r, g, b, a) = input.GetPixel(x, y);

                // Blend at overlap seams
                var isOverlapX = overlap > 0f && tx > 0 && x < (int)(overlap * tileSize);
                var isOverlapY = overlap > 0f && ty > 0 && y < (int)(overlap * tileSize);

                if (isOverlapX || isOverlapY)
                {
                    var (er, eg, eb, ea) = buffer.GetPixel(bx, by);
                    var blendT = 0.5f;
                    r = Lerp(er, r, blendT);
                    g = Lerp(eg, g, blendT);
                    b = Lerp(eb, b, blendT);
                    a = Math.Max(ea, a);
                }

                buffer.SetPixel(bx, by, r, g, b, a);
            }
        }
    }
}

return buffer;
}
